253	type OpenAIImageEditInput = {
254	  /**
255	   * Allows to set transparency for the background of the generated image(s).
256	   * This parameter is only supported for `gpt-image-1`. Must be one of
257	   * `transparent`, `opaque` or `auto` (default value). When `auto` is used, the
258	   * model will automatically determine the best background for the image.
259	   *
260	   * If `transparent`, the output format needs to support transparency, so it
261	   * should be set to either `png` (default value) or `webp`.
262	   *
263	   */
264	  background?: 'transparent' | 'opaque' | 'auto';
265	  /**
266	   * The image(s) to edit. Must be a supported image file or an array of images.
267	   *
268	   * For `gpt-image-1`, each image should be a `png`, `webp`, or `jpg` file less
269	   * than 50MB. You can provide up to 16 images.
270	   *
271	   * For `dall-e-2`, you can only provide one image, and it should be a square
272	   * `png` file less than 4MB.
273	   *
274	   */
275	  image: Blob | Blob[];
276	  input_fidelity?: ('high' | 'low') | null;
277	  /**
278	   * An additional image whose fully transparent areas (e.g. where alpha is zero) indicate where `image` should be edited. If there are multiple images provided, the mask will be applied on the first image. Must be a valid PNG file, less than 4MB, and have the same dimensions as `image`.
279	   */
280	  mask?: Blob;
281	  /**
282	   * The model to use for image generation. Only `dall-e-2` and `gpt-image-1` are supported. Defaults to `dall-e-2` unless a parameter specific to `gpt-image-1` is used.
283	   */
284	  model?: 'dall-e-2' | 'gpt-image-1' | 'gpt-image-1-mini' | (string & {});
285	  /**
286	   * The number of images to generate. Must be between 1 and 10.
287	   */
288	  n?: number;
289	  /**
290	   * The compression level (0-100%) for the generated images. This parameter
291	   * is only supported for `gpt-image-1` with the `webp` or `jpeg` output
292	   * formats, and defaults to 100.
293	   *
294	   */
295	  output_compression?: number;
296	  /**
297	   * The format in which the generated images are returned. This parameter is
298	   * only supported for `gpt-image-1`. Must be one of `png`, `jpeg`, or `webp`.
299	   * The default value is `png`.
300	   *
301	   */
302	  output_format?: 'png' | 'jpeg' | 'webp';
303	  partial_images?: number | null;
304	  /**
305	   * A text description of the desired image(s). The maximum length is 1000 characters for `dall-e-2`, and 32000 characters for `gpt-image-1`.
306	   */
307	  prompt?: string;
308	  /**
309	   * The quality of the image that will be generated. `high`, `medium` and `low` are only supported for `gpt-image-1`. `dall-e-2` only supports `standard` quality. Defaults to `auto`.
310	   *
311	   */
312	  quality?: 'standard' | 'low' | 'medium' | 'high' | 'auto';
313	  /**
314	   * The format in which the generated images are returned. Must be one of `url` or `b64_json`. URLs are only valid for 60 minutes after the image has been generated. This parameter is only supported for `dall-e-2`, as `gpt-image-1` will always return base64-encoded images.
315	   */
316	  response_format?: 'url' | 'b64_json';
317	  /**
318	   * The size of the generated images. Must be one of `1024x1024`, `1536x1024` (landscape), `1024x1536` (portrait), or `auto` (default value) for `gpt-image-1`, and one of `256x256`, `512x512`, or `1024x1024` for `dall-e-2`.
319	   */
320	  size?: `${number}x${number}`;
321	  /**
322	   * Edit the image in streaming mode. Defaults to `false`. See the
323	   * [Image generation guide](https://platform.openai.com/docs/guides/image-generation) for more information.
324	   *
325	   */
326	  stream?: boolean;
327	  /**
328	   * A unique identifier representing your end-user, which can help OpenAI to monitor and detect abuse. [Learn more](https://platform.openai.com/docs/guides/safety-best-practices#end-user-ids).
329	   *
330	   */
331	  user?: string;
332	};
